import{_ as a,o as e,c as l,a2 as o}from"./chunks/framework.BQ1gajhD.js";const g=JSON.parse('{"title":"石舫（清晏舫）","description":"","frontmatter":{},"headers":[],"relativePath":"landmarks/summer-palace/shifang.md","filePath":"landmarks/summer-palace/shifang.md","lastUpdated":1784720050000}'),r={name:"landmarks/summer-palace/shifang.md"};function n(i,t,s,d,u,h){return e(),l("div",null,[...t[0]||(t[0]=[o('<h1 id="石舫-清晏舫" tabindex="-1">石舫（清晏舫） <a class="header-anchor" href="#石舫-清晏舫" aria-label="Permalink to &quot;石舫（清晏舫）&quot;">​</a></h1><p><img src="https://images.unsplash.com/photo-1614006620172-ce0fb5969981?w=1200&amp;q=80" alt="石舫清晏舫"></p><blockquote><p>&quot;水能载舟，亦能覆舟。&quot; —— 一座永不沉没的石船，一句被历史反复印证的箴言</p></blockquote><h2 id="简介" tabindex="-1">简介 <a class="header-anchor" href="#简介" aria-label="Permalink to &quot;简介&quot;">​</a></h2><p>石舫位于昆明湖西北岸边、万寿山西麓，俗称&quot;石舫&quot;，正式名称&quot;清晏舫&quot;，是颐和园中最富象征意味的建筑。它全长36米，船体由巨大的青石雕砌而成，下承石基插入湖中，远望如一艘泊岸的画舫，近看方知是&quot;以石为舟&quot;的巧构。</p><p>这座永远不会沉没、也永远不会离岸的船，是乾隆朝留下的造园妙笔，也是晚清历史最辛辣的反讽。</p><p>石舫始建于乾隆二十年（1755年）。乾隆取&quot;水能载舟，亦能覆舟&quot;的古训建此石舫，寓意江山如舟、百姓如水，告诫子孙为君者当敬畏民心；又因石舫永固不沉，象征大清基业&quot;磐石之安&quot;。</p><p>咸丰十年（1860年）英法联军焚园，舫上中式木构舱楼尽毁，唯石质船身在大火中岿然独存。光绪年间慈禧重建时，将中式舱楼改为西式舱楼，并更名&quot;清晏舫&quot;，取&quot;河清海晏、天下太平&quot;之意。</p><h2 id="历史沿革" tabindex="-1">历史沿革 <a class="header-anchor" href="#历史沿革" aria-label="Permalink to &quot;历史沿革&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">年代</th><th style="text-align:left;">大事</th></tr></thead><tbody><tr><td style="text-align:left;">清乾隆二十年（1755）</td><td style="text-align:left;">始建石舫，上为中式舱楼，寓&quot;水能载舟亦能覆舟&quot;</td></tr><tr><td style="text-align:left;">咸丰十年（1860）</td><td style="text-align:left;">英法联军焚园，木构舱楼尽毁，石船身独存</td></tr><tr><td style="text-align:left;">清光绪年间</td><td style="text-align:left;">慈禧重建，舱楼改为西式，更名&quot;清晏舫&quot;</td></tr><tr><td style="text-align:left;">1924年</td><td style="text-align:left;">随颐和园对外开放</td></tr><tr><td style="text-align:left;">当代</td><td style="text-align:left;">昆明湖游船主码头之一，为全园最热门拍照点</td></tr></tbody></table><h2 id="建筑与景观" tabindex="-1">建筑与景观 <a class="header-anchor" href="#建筑与景观" aria-label="Permalink to &quot;建筑与景观&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">项目</th><th style="text-align:left;">内容</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>全长</strong></td><td style="text-align:left;">36米，船体以巨石雕砌</td></tr><tr><td style="text-align:left;"><strong>船身</strong></td><td style="text-align:left;">乾隆朝青石船体，两侧各有一只仿明轮蒸汽船的石轮，船首雕石锚、缆桩</td></tr><tr><td style="text-align:left;"><strong>舱楼</strong></td><td style="text-align:left;">光绪朝西式两层舱楼，大理石纹饰面、西洋彩色玻璃窗、法式花砖瓦顶</td></tr><tr><td style="text-align:left;"><strong>命名</strong></td><td style="text-align:left;">重建后更名&quot;清晏舫&quot;，取&quot;河清海晏&quot;之意</td></tr><tr><td style="text-align:left;"><strong>相邻建筑</strong></td><td style="text-align:left;">东侧听鹂馆（皇家戏台旧址，今宫廷菜餐厅）</td></tr></tbody></table><p>如今的清晏舫，下半部是乾隆朝的石船身，上半部则是慈禧时期的西式舱楼，中西合璧，在满园亭台楼阁中显得格外特别。</p><p>舫旁临水处原与岸相连，舫内旧陈西洋镜、自鸣钟等器物，是清宫中最早接受&quot;西风&quot;的角落之一。</p><h2 id="历史故事" tabindex="-1">历史故事 <a class="header-anchor" href="#历史故事" aria-label="Permalink to &quot;历史故事&quot;">​</a></h2><h3 id="乾隆的-警示之舟" tabindex="-1">乾隆的&quot;警示之舟&quot; <a class="header-anchor" href="#乾隆的-警示之舟" aria-label="Permalink to &quot;乾隆的&quot;警示之舟&quot;&quot;">​</a></h3><p>乾隆建石舫时曾为文记之，引唐太宗与魏征&quot;水能载舟，亦能覆舟&quot;的对话，告诫后世子孙：君王是舟，百姓是水，水可载舟亦可覆舟，故以巨石为舟，立于昆明湖畔，望后人时刻警醒。立意不可谓不深远。然而百余年后，这座&quot;警示之舟&quot;亲眼见证了它的建造者们如何一步步背离祖训——石船不沉，王朝却沉了。</p><h3 id="海军军费换来的西洋舱楼" tabindex="-1">海军军费换来的西洋舱楼 <a class="header-anchor" href="#海军军费换来的西洋舱楼" aria-label="Permalink to &quot;海军军费换来的西洋舱楼&quot;">​</a></h3><p>1886年重建清晏舫时，正值北洋水师筹建之际。慈禧以&quot;昆明湖习水操&quot;为名，从海军经费中腾挪巨款修缮园林，其中就包括将石舫舱楼改建为时髦的西式风格：法国瓦、彩色玻璃、大理石贴面……而本该用于购置军舰的银子，化作了舫上的花砖。</p><p>仅仅八年之后，甲午海战爆发，北洋水师全军覆没。此后民间流传一句话：&quot;昆明湖上添一层玻璃，黄海上便少一艘军舰。&quot;石舫犹在，警钟长鸣。</p><h3 id="一场火烧出的-时间胶囊" tabindex="-1">一场火烧出的&quot;时间胶囊&quot; <a class="header-anchor" href="#一场火烧出的-时间胶囊" aria-label="Permalink to &quot;一场火烧出的&quot;时间胶囊&quot;&quot;">​</a></h3><p>1860年的大火烧了三天三夜，万寿山下林木建筑尽成焦土，唯独这座石船身在大火中安然无恙——它本是&quot;警示&quot;的象征，却以最讽刺的方式完成了自己的证言：木质的繁华可以一夜焚尽，石质的箴言却烧不掉。</p><p>慈禧重建时没有恢复中式舱楼，而是换上了当时最时髦的西洋风格，仿佛在说：旧的教训不够，要用新的时髦来覆盖。两层建筑，两个时代，叠在同一艘船上，这就是清晏舫最耐读的地方。</p><h2 id="必看亮点" tabindex="-1">必看亮点 <a class="header-anchor" href="#必看亮点" aria-label="Permalink to &quot;必看亮点&quot;">​</a></h2><ol><li><strong>石船身与西式舱楼的混搭</strong>：乾隆朝的青石船身托着慈禧时期的法式舱楼，一舫阅尽两个时代，是园林建筑中罕见的&quot;时间叠层&quot;。</li><li><strong>明轮船轮与石锚</strong>：船身两侧仿蒸汽船的石轮、船首的石锚缆桩，细节处可见晚清对西洋器物的想象。</li><li><strong>彩色玻璃窗</strong>：舱楼窗户嵌西洋彩色玻璃，阳光透入时五色斑斓，是当年宫廷中最时髦的&quot;装修&quot;。</li><li><strong>湖上回望</strong>：乘船离开石舫码头后回望，石舫与万寿山佛香阁同框，是颐和园明信片级的经典画面。</li><li><strong>听鹂馆比邻</strong>：石舫东侧即听鹂馆（皇家戏台旧址），如今是宫廷风味餐厅，逛累了可在此歇脚用餐。</li></ol><h2 id="拍照机位" tabindex="-1">拍照机位 <a class="header-anchor" href="#拍照机位" aria-label="Permalink to &quot;拍照机位&quot;">​</a></h2><ol><li><strong>码头正面</strong>：从岸边码头平视船身，能同时拍到石锚、船轮与西式舱楼全貌，上午顺光最佳。</li><li><strong>湖上回望</strong>：游船离岸五十米回望，石舫、长廊、佛香阁三层构图一气呵成。</li><li><strong>细节特写</strong>：彩色玻璃窗与大理石纹饰面适合侧光特写，质感一流。</li></ol><h2 id="参观贴士" tabindex="-1">参观贴士 <a class="header-anchor" href="#参观贴士" aria-label="Permalink to &quot;参观贴士&quot;">​</a></h2><ol><li>石舫不可登舫入内（文物保护），只能沿岸边与码头上近距离观赏外观，请预留20-30分钟细看细节。</li><li>这里是昆明湖游船的主要码头之一，逛完石舫可直接乘船前往南湖岛、<a href="/beijing-travel-guide/landmarks/summer-palace/kunming-lake.html">十七孔桥</a>，省力又出片。</li><li>上午顺光，石船身与白大理石纹饰拍照最清晰；傍晚逆光剪影也别有韵味。</li><li>从<a href="/beijing-travel-guide/landmarks/summer-palace/changlang.html">长廊</a>西端的石丈亭出来即达，是长廊动线的自然终点。</li><li>若走<a href="/beijing-travel-guide/landmarks/summer-palace/">北宫门线</a>，石舫恰在佛香阁下山之后、登船之前，承上启下，别错过。</li><li>给小朋友讲讲&quot;石头船为什么沉不了&quot;，比任何课本都直观。</li></ol><h2 id="常见问题" tabindex="-1">常见问题 <a class="header-anchor" href="#常见问题" aria-label="Permalink to &quot;常见问题&quot;">​</a></h2><p><strong>Q：石舫可以上船参观吗？</strong></p><p>不能。清晏舫属重点保护文物，四周设护栏，只能在岸边和码头近距离观赏外观。</p><p><strong>Q：石舫为什么叫&quot;清晏舫&quot;？</strong></p><p>原名&quot;石舫&quot;，光绪年间慈禧重建西式舱楼后更名&quot;清晏舫&quot;，取&quot;河清海晏、天下太平&quot;之意——只是彼时的&quot;海晏&quot;，多少有些自我安慰。</p><p><strong>Q：石舫真的是石头做的吗？</strong></p><p>船体（下部的船身、船轮、石锚）确实是巨石雕砌；上部的舱楼则是木构，如今所见为光绪年间的西式舱楼。</p><p><strong>Q：石舫附近哪里可以吃饭歇脚？</strong></p><p>东侧听鹂馆是著名的宫廷菜餐厅（价格偏高）；北宫门内也有快餐区；想省钱可自带干粮在湖边长椅野餐。</p><hr><p><strong>📍 位置</strong>：昆明湖西北岸，万寿山西麓，长廊西端附近 <strong>⏱️ 建议游览</strong>：20-30分钟 <strong>🔗 返回</strong>：<a href="/beijing-travel-guide/landmarks/summer-palace/">颐和园概览</a></p>',40)])])}const p=a(r,[["render",n]]);export{g as __pageData,p as default};
